211‚Üí              fontSize: '0.75rem', fontWeight: 800, animation: 'pulse 1.5s infinite'
212‚Üí            }}>{pendingCount}</span>
213‚Üí          )}
214‚Üí        </h2>
215‚Üí        {(user.role === 'MASTER' || user.role === 'ADMIN' || user.role === 'NAZORATCHI' || user.role === 'UZLAVYAZ') && (
216‚Üí          <button onClick={() => { setShowCallForm(!showCallForm); setShowReasons(false); setSelectedReasons([]); setCustomReason(''); }} style={{
217‚Üí            display: 'flex', alignItems: 'center', gap: '6px', padding: '10px 16px',
218‚Üí            background: '#ef4444', color: 'white', border: 'none', borderRadius: '10px',
219‚Üí            cursor: 'pointer', fontWeight: 700, fontSize: '0.85rem'
220‚Üí          }}>
221‚Üí            <AlertTriangle size={16} /> Chaqiruv Yuborish
222‚Üí          </button>
223‚Üí        )}
224‚Üí      </div>
225‚Üí
226‚Üí      {showCallForm && (
227‚Üí        <div style={{
228‚Üí          background: 'var(--card)', border: '1px solid var(--panel-border)', borderRadius: '16px',
229‚Üí          padding: '1.5rem', marginBottom: '1.5rem'
230‚Üí        }}>
231‚Üí          <h3 style={{ margin: '0 0 1rem 0', fontSize: '1rem', fontWeight: 700 }}>Yangi Chaqiruv</h3>
232‚Üí
233‚Üí          <div style={{ marginBottom: '1rem' }}>
234‚Üí            <label style={labelStyle}>Stanok</label>
235‚Üí            <select className="input-field" style={{ marginTop: '4px' }}
236‚Üí              value={callForm.machine_id}
237‚Üí              onChange={e => setCallForm({ ...callForm, machine_id: e.target.value })}>
238‚Üí              <option value="">Tanlang...</option>
239‚Üí              {allMachineIds.map(id => <option key={id} value={id}>{id}</option>)}
240‚Üí            </select>
241‚Üí          </div>
242‚Üí
243‚Üí          <label style={labelStyle}>Signal Turi</label>
