274‚Üí                  <button key={reason} onClick={() => toggleReason(reason)} style={{
275‚Üí                    padding: '8px 16px', borderRadius: '20px',
276‚Üí                    border: `2px solid ${isSelected ? (isOther ? '#a855f7' : '#22c55e') : 'rgba(255,255,255,0.1)'}`,
277‚Üí                    background: isSelected ? (isOther ? 'rgba(168,85,247,0.2)' : 'rgba(34,197,94,0.15)') : 'rgba(255,255,255,0.03)',
278‚Üí                    color: isSelected ? (isOther ? '#a855f7' : '#22c55e') : 'var(--text-muted)',
279‚Üí                    cursor: 'pointer', fontWeight: 600, fontSize: '0.8rem',
280‚Üí                    transition: 'all 0.2s ease',
281‚Üí                  }}>
282‚Üí                    {isSelected ? '‚úì ' : ''}{reason}
283‚Üí                  </button>
284‚Üí                );
285‚Üí              })}
286‚Üí            </div>
287‚Üí
288‚Üí            {hasOther && (
